SELECT * FROM oms_order WHERE delete_status = 0
AND order_sn LIKE concat("%",#{queryParam.orderSn},"%")
AND `status` = #{queryParam.status}
AND source_type = #{queryParam.sourceType}
AND order_type = #{queryParam.orderType}
AND create_time LIKE concat(#{queryParam.createTime},"%")
AND ( receiver_name LIKE concat("%",#{queryParam.receiverKeyword},"%") OR receiver_phone LIKE concat("%",#{queryParam.receiverKeyword},"%") )
ORDER BY create_time DESC
